import android.content.Context;
import android.content.SharedPreferences;
import android.hardware.fingerprint.FingerprintManager;
import android.os.Build;
import android.support.annotation.RequiresApi;
import android.widget.Toast;
import java.util.ArrayList;
import java.util.List;

@RequiresApi(api = Build.VERSION_CODES.M)
public class FingerprintAuth {
    private static final String TAG = "FingerprintAuth";
    private static final String PREF_AUTHENTICATED = "authenticated";
    private SharedPreferences prefs;
    private FingerprintManager mFingerprintManager;
    private boolean authenticated;

    public FingerprintAuth(Context context) {
        this.prefs = context.getSharedPreferences("fingerprint_auth", Context.MODE_PRIVATE);
        this.authenticated = prefs.getBoolean(PREF_AUTHENTICATED, false);
        mFingerprintManager = (FingerprintManager) context.getSystemService(Context.FINGERPRINT_SERVICE);
    }

    public boolean isAuthenticated() {
        return authenticated;
    }

    public void setAuthenticated(boolean authenticated) {
        this.authenticated = authenticated;
        prefs.edit().putBoolean(PREF_AUTHENTICATED, authenticated).apply();
    }

    public void authenticate(String title, String subtitle) {
        if (mFingerprintManager != null && mFingerprintManager.isHardwareDetected()) {
            List<FingerprintManager.AuthenticationCallback> callbacks = new ArrayList<>();
            callbacks.add(new FingerprintManager.AuthenticationCallback() {
                @Override
                public void onAuthenticationError(int errorCode, CharSequence errString) {
                    Toast.makeText(context, "Authentication error: " + errString, Toast.LENGTH_SHORT).show();
                }

                @Override
                public void onAuthenticationHelp(int helpCode, CharSequence helpString) {
                    Toast.makeText(context, "Authentication help: " + helpString, Toast.LENGTH_SHORT).show();
                }

                @Override
                public void onAuthenticationSucceeded(FingerprintManager.AuthenticationResult result) {
                    setAuthenticated(true);
                }

                @Override
                public void onAuthenticationFailed() {
                    Toast.makeText(context, "Authentication failed", Toast.LENGTH_SHORT).show();
                }
            });

            mFingerprintManager.authenticate(null, 0, null, callbacks, null);
        } else {
            Toast.makeText(context, "Fingerprint sensor not detected", Toast.LENGTH_SHORT).show();
        }
    }
}